  @Test
  public void fromJSON_basicLink()
  {
    String json = "{\"featureModel\":{\"name\":\"M\",\"nodes\":["
        + "{\"id\":1,\"uniqueName\":\"A\",\"name\":\"A\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null},"
        + "{\"id\":2,\"uniqueName\":\"B\",\"name\":\"B\",\"nodeType\":\"FeatureLeaf\",\"isLeaf\":true,\"isCompoundFeature\":false,\"mixsetOrFileNode\":null}"
        + "],\"links\":["
        + "{\"sourceNodeId\":1,\"targetNodeId\":2,\"linkType\":\"FeatureLink\",\"opType\":\"Mandatory\",\"isSub\":true}"
        + "]}}";
    FeatureModel model = FeatureModel.fromJSON(json);
    Assert.assertEquals(1, model.numberOfFeaturelink());
    FeatureLink link = model.getFeaturelink(0);
    Assert.assertEquals(FeatureConnectingOpType.Mandatory, link.getFeatureConnectingOpType());
    Assert.assertTrue(link.getIsSub());
    Assert.assertEquals("A", link.getSourceFeatureNode().getName());
    Assert.assertEquals("B", link.getTargetFeatureNode().getName());
  }

