    FeatureLeaf leaf = (FeatureLeaf) fm.getNode(0);
    Mixset mixset = (Mixset) leaf.getMixsetOrFileNode();
    ReqImplementation ri = mixset.getReqImplementation(0);
    Assert.assertNull(ri.getImplementingFeature());
