  @Test
  public void roundTrip_complexModelPreservesStructure()
  {
    FeatureModel original = new FeatureModel("FullModel");

    // Create a tree: Root (compound) -> [A (leaf+mixset), B (leaf), C (fragment)]
    CompoundFeatureNode root = new CompoundFeatureNode(original);
    root.setName("Root");

    FeatureLeaf a = new FeatureLeaf(original);
    a.setName("A");
    Mixset mixA = new Mixset("MixA");
    mixA.setIsFeature(true);
    a.setMixsetOrFileNode(mixA);

    FeatureLeaf b = new FeatureLeaf(original);
    b.setName("B");

    FragmentFeatureLeaf c = new FragmentFeatureLeaf(original);
    c.setName("C");

    root.addChildFeature(a);
    root.addChildFeature(b);
    root.addChildFeature(c);

    // Mandatory link root->a
    FeatureLink mandLink = new FeatureLink();
    mandLink.setSourceFeatureNode(root);
    mandLink.setTargetFeatureNode(a);
    mandLink.setFeatureConnectingOpType(FeatureConnectingOpType.Mandatory);
    mandLink.setIsSub(true);
    mandLink.setFeatureModel(original);

    // Optional link root->b
    FeatureLink optLink = new FeatureLink();
    optLink.setSourceFeatureNode(root);
    optLink.setTargetFeatureNode(b);
    optLink.setFeatureConnectingOpType(FeatureConnectingOpType.Optional);
    optLink.setIsSub(true);
    optLink.setFeatureModel(original);

    // XOR link root->c
    XORFeatureConnectingOpType xorLink = new XORFeatureConnectingOpType();
    xorLink.setSourceFeatureNode(root);
    xorLink.setTargetFeatureNode(c);
    xorLink.setFeatureModel(original);

    String json = original.toJSON();
    FeatureModel restored = FeatureModel.fromJSON(json);

    Assert.assertEquals("FullModel", restored.getName());
    Assert.assertEquals(4, restored.numberOfNode());
    Assert.assertEquals(3, restored.numberOfFeaturelink());

    // Verify node types survive round-trip
    int leafCount = 0, compoundCount = 0, fragmentCount = 0;
    for (FeatureNode n : restored.getNode())
    {
      if (n instanceof CompoundFeatureNode) { compoundCount++; }
      else if (n instanceof FragmentFeatureLeaf) { fragmentCount++; }
      else if (n instanceof FeatureLeaf) { leafCount++; }
    }
    Assert.assertEquals(2, leafCount);
    Assert.assertEquals(1, compoundCount);
    Assert.assertEquals(1, fragmentCount);
  }

